/* ------------------------- sub-components --------------------------- */
function describeArc(cx: number, cy: number, r: number, a0: number, a1: number) {
  const p0 = [cx + r * Math.cos(a0 * DEG), cy + r * Math.sin(a0 * DEG)];
  const p1 = [cx + r * Math.cos(a1 * DEG), cy + r * Math.sin(a1 * DEG)];
  const large = a1 - a0 <= 180 ? 0 : 1;
  return `M${p0[0]} ${p0[1]} A${r} ${r} 0 ${large} 1 ${p1[0]} ${p1[1]}`;
}
function wave(w: number, h: number, t: number, freq: number, seed: string) {
  const n = 60; let s = "";
  for (let i = 0; i <= n; i++) {
    const x = (i / n) * w;
    const y = h / 2 + Math.sin(i * 0.5 + t * freq) * h * 0.22 * (0.6 + 0.4 * Math.sin(i * 0.2 + t)) +
      Math.sin(i * 1.4 + t * 3 + random(seed).valueOf()) * h * 0.1;
    s += `${x.toFixed(1)},${y.toFixed(1)} `;
  }
  return s;
}

const Shield: React.FC<{ s: number; c: string; t: number }> = ({ s, c, t }) => (
  <svg width={s} height={s} viewBox="0 0 40 40" style={{ filter: `drop-shadow(0 0 ${s * 0.14}px ${c})` }}>
    <path d="M20 3 L34 8 V19 C34 29 28 35 20 38 C12 35 6 29 6 19 V8 Z" fill="none" stroke={c} strokeWidth={2.4} strokeLinejoin="round" />
    <path d="M14 20 L18 25 L27 14" fill="none" stroke={c} strokeWidth={2.6} strokeLinecap="round" strokeLinejoin="round"
      opacity={0.5 + 0.5 * Math.sin(t * 3)} />
  </svg>
);

const MiniWave: React.FC<{ w: number; h: number; c: string; t: number; seed: string }> = ({ w, h, c, t, seed }) => (
  <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`}>
    <polyline points={wave(w, h, t, 2.6, seed)} fill="none" stroke={c} strokeWidth={1.6} opacity={0.9} />
  </svg>
);

const Gauge: React.FC<{ cx: number; cy: number; r: number; pct: number; color: string; label: string; S: (v: number) => number }> =
  ({ cx, cy, r, pct, color, label, S }) => {
    const a1 = 135 + 270 * (pct / 100);
    const needle = a1 * DEG;
    return (
      <g>
        <path d={describeArc(cx, cy, r, 135, 405)} fill="none" stroke="rgba(255,255,255,0.12)" strokeWidth={S(9)} strokeLinecap="round" />
        <path d={describeArc(cx, cy, r, 135, a1)} fill="none" stroke={color} strokeWidth={S(9)} strokeLinecap="round" style={{ filter: `drop-shadow(0 0 ${S(5)}px ${color})` }} />
        <line x1={cx} y1={cy} x2={cx + r * 0.7 * Math.cos(needle)} y2={cy + r * 0.7 * Math.sin(needle)} stroke="#fff" strokeWidth={S(2)} strokeLinecap="round" />
        <circle cx={cx} cy={cy} r={S(4)} fill="#fff" />
        <text x={cx} y={cy + r + S(24)} textAnchor="middle" fontFamily={FONT} fontWeight={700} fontSize={S(12)} fill={K.dim} letterSpacing="0.08em">{label}</text>
        <text x={cx} y={cy + S(30)} textAnchor="middle" fontFamily={FONT} fontWeight={800} fontSize={S(19)} fill={K.text}>{pct}%</text>
      </g>
    );
  };

const Donut: React.FC<{ cx: number; cy: number; r: number; t: number; S: (v: number) => number }> = ({ cx, cy, r, t, S }) => {
  const segs = [
    { v: 31, c: K.red }, { v: 24, c: K.amber }, { v: 18, c: K.cyan }, { v: 15, c: K.purple }, { v: 12, c: K.green },
  ];
  let acc = -90; const total = segs.reduce((a, b) => a + b.v, 0);
  return (
    <g transform={`rotate(${t * 6} ${cx} ${cy})`}>
      {segs.map((s, i) => {
        const a0 = acc, a1 = acc + (s.v / total) * 360; acc = a1;
        return <path key={i} d={describeArc(cx, cy, r, a0, a1 - 2)} fill="none" stroke={s.c} strokeWidth={S(15)} />;
      })}
      <text x={cx} y={cy + S(5)} textAnchor="middle" fontFamily={FONT} fontWeight={800} fontSize={S(14)} fill={K.text} transform={`rotate(${-t * 6} ${cx} ${cy})`}>TYPE</text>
    </g>
  );
};
